// Extract DM data from Meta webhook payload
const body = $input.first().json.body;
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging?.message?.text) {
  return [{ json: { skip: true } }];
}

const senderId = messaging.sender.id;
const pageId = entry.id;
const messageText = messaging.message.text;
const messageId = messaging.message.mid;

return [{
  json: {
    ig_user_id: senderId,
    ig_page_id: pageId,
    ig_thread_id: `${pageId}_${senderId}`,
    message_text: messageText,
    ig_message_id: messageId,
    timestamp: new Date().toISOString()
  }
}];

// Merge DM data with profile info
const dm = $('Extract DM Data').first().json;
const profile = $input.first().json;

return [{
  json: {
    ...dm,
    username: profile.username || 'unknown',
    display_name: profile.name || profile.username || 'Unknown'
  }
}];

// Build conversation history for Claude context
const dm = $('Merge Profile').first().json;
const historyResponse = $input.first().json;
const messages = historyResponse?.messages || [];

// Format conversation history
let conversationHistory = '';
if (messages.length > 0) {
  conversationHistory = '\n\nPREVIOUS CONVERSATION HISTORY:\n';
  for (const msg of messages) {
    const role = msg.direction === 'inbound' ? dm.username : 'You (AI/Agent)';
    conversationHistory += `${role}: ${msg.content}\n`;
  }
}

return [{
  json: {
    ...dm,
    conversation_history: conversationHistory,
    message_count: messages.length
  }
}];

