// Build final payload with AI reply + AI classification
const dm = $('Build Claude Context').first().json;
const replyResponse = $('Claude — Generate Reply (with History)').first().json;
const classifyResponse = $('Claude — Classify Lead Status').first().json;

// Extract AI reply text
const aiReply = replyResponse?.content?.[0]?.text || 'Unable to generate reply';

// Extract classification (clean it up)
const rawStatus = (classifyResponse?.content?.[0]?.text || 'active').trim().toLowerCase();
const validStatuses = ['active', 'qualified', 'booked', 'closed'];
const aiStatus = validStatuses.includes(rawStatus) ? rawStatus : 'active';

return [{
  json: {
    account_id: dm.account_id || '',
    ig_thread_id: dm.ig_thread_id,
    ig_user_id: dm.ig_user_id,
    ig_message_id: dm.ig_message_id,
    username: dm.username,
    display_name: dm.display_name,
    message: dm.message_text,
    direction: 'inbound',
    status: aiStatus,
    ai_status: aiStatus,
    pending_ai_draft: aiReply,
    is_ai: false,
    ai_reply: aiReply,
    message_count: dm.message_count
  }
}];

// Process each pending sequence enrollment
const enrollments = $input.first().json;
if (!Array.isArray(enrollments) || enrollments.length === 0) {
  return [{ json: { skip: true, message: 'No pending sequence steps' } }];
}

const results = [];
for (const enrollment of enrollments) {
  const steps = enrollment.sequence_steps || [];
  const currentStep = steps.find(s => s.step_order === enrollment.current_step);

  if (!currentStep) {
    results.push({
      json: {
        enrollment_id: enrollment.id,
        action: 'complete',
        message: 'No more steps'
      }
    });
    continue;
  }

  // Replace template variables
  let messageText = currentStep.message_template;
  if (enrollment.dm_threads) {
    messageText = messageText
      .replace('{{username}}', enrollment.dm_threads.username || '')
      .replace('{{display_name}}', enrollment.dm_threads.display_name || '');
  }

  results.push({
    json: {
      enrollment_id: enrollment.id,
      sequence_id: enrollment.sequence_id,
      thread_id: enrollment.thread_id,
      ig_user_id: enrollment.dm_threads?.ig_user_id,
      current_step: enrollment.current_step,
      total_steps: steps.length,
      message: messageText,
      action: 'send'
    }
  });
}

return results;
